// Merge expiring and high-usage into deduplicated list
const inputs = $input.all();
const seen = new Set();
const combined = [];

for (const item of inputs) {
    const order = item.json;
    if (!seen.has(order.id)) {
        seen.add(order.id);
        // Determine reason
        if (order.expires_at && new Date(order.expires_at) <= new Date(Date.now() + 7*24*60*60*1000)) {
            order.reminder_type = 'expiry';
            const daysLeft = Math.ceil((new Date(order.expires_at) - new Date()) / (24*60*60*1000));
            order.message = `⚠️ Your ${order.product} proxy expires in ${daysLeft} day${daysLeft === 1 ? '' : 's'}. Reply RENEW to keep access.`;
        }
        if (order.data_used_gb && order.data_limit_gb) {
            const pct = Math.round((order.data_used_gb / order.data_limit_gb) * 100);
            order.data_pct = pct;
            order.message = order.message || `📊 You've used ${pct}% of your ${order.data_limit_gb}GB ${order.product} data. Reply UPGRADE for more.`;
        }
        combined.push({ json: order });
    }
}
return combined;
